/* ─── INVOICE DATE HELPERS ─── */
const LOGO_WM = "data:image/svg+xml;base64,";

function lastDayPrevMonth(issueDateStr) {
  const d = issueDateStr ? new Date(issueDateStr) : new Date();
  return new Date(d.getFullYear(), d.getMonth(), 0).toISOString().slice(0, 10);
}
function nextDueDate(issueDateStr) {
  const d = issueDateStr ? new Date(issueDateStr) : new Date();
  const due = new Date(d.getFullYear(), d.getMonth(), 15);
  return due.toISOString().slice(0, 10);
}
function adjustDueDate(base, offsetDays) {
  // base is "YYYY-MM-15", offset is -5..+5
  const d = new Date(base);
  d.setDate(d.getDate() + offsetDays);
  return d.toISOString().slice(0, 10);
}

/* ─── INVOICE ISSUE MODAL ─── */
function InvoiceIssueModal({ clientId, entries, clients, invoices, onConfirm, onCancel, saving }) {
  const client = clients.find(c => c.id === clientId);
  const [selected, setSelected] = useState(() => new Set(entries.map(e => e.id)));
  const [invoiceNo, setInvoiceNo] = useState(() => nextInvoiceNumber(invoices));
  const [issueDate, setIssueDate] = useState(() => today());
  const [dueDateBase, setDueDateBase] = useState(() => nextDueDate(today()));
  const [dueDateOffset, setDueDateOffset] = useState(0); // -5..+5
  const [varSymbol, setVarSymbol] = useState(() => {
    const next = nextInvoiceNumber(invoices);
    return next.replace(/[^0-9]/g, "").slice(-6) || String(new Date().getFullYear()).slice(2) + String(invoices.length + 1).padStart(3, "0");
  });
  const [showPreview, setShowPreview] = useState(false);

  const dueDate = adjustDueDate(dueDateBase, dueDateOffset);
  const duzp    = lastDayPrevMonth(issueDate);

  const selEntries = entries.filter(e => selected.has(e.id));
  const workAmt = selEntries.reduce((s, e) => s + (e.amount || 0), 0);
  const notary = selEntries.reduce((s, e) => s + (e.notary_fee || 0), 0);
  const admin = selEntries.reduce((s, e) => s + (e.admin_fee || 0), 0);
  const vat = Math.round(workAmt * 0.21);
  const total = workAmt + vat + notary + admin;

  const toggle = (id) => setSelected(p => { const n = new Set(p); n.has(id) ? n.delete(id) : n.add(id); return n; });

  const invoice = {
    id: uid(), invoice_number: invoiceNo,
    client_id: clientId, issue_date: issueDate, due_date: dueDate, duzp,
    items: [
      ...selEntries.filter(e => e.hours > 0 || e.billing_type === "flat_rate").map(e => ({ id: uid(), description: e.description, hours: e.hours, rate: e.rate, amount: e.amount, no_vat: false, flat_rate: e.billing_type === "flat_rate" })),
      ...(notary > 0 ? [{ id: uid(), description: "Přefakturace — notář", hours: 0, rate: 0, amount: notary, no_vat: true }] : []),
      ...(admin > 0 ? [{ id: uid(), description: "Správní poplatek — přefakturace", hours: 0, rate: 0, amount: admin, no_vat: true }] : []),
    ],
    subtotal: workAmt, vat_rate: 21, vat_amount: vat, total,
    status: "pripravena", notes: varSymbol,
    var_symbol: varSymbol,
  };

  if (showPreview) {
    return <InvoicePrintPreview invoice={invoice} client={client} workEntries={selEntries}
      onBack={() => setShowPreview(false)}
      onIssue={(sent) => onConfirm({ ...invoice, status: sent ? "vystavena" : "pripravena" }, selEntries.map(e => e.id))}
      saving={saving} />;
  }

  const stepStyle = { width: 28, height: 28, borderRadius: 6, border: "1px solid var(--line)", background: "#fff", cursor: "pointer", fontSize: 16, color: "var(--ink)", display:"flex", alignItems:"center", justifyContent:"center", userSelect:"none", flexShrink:0 };

  return (
    <div className="ov" onClick={onCancel}>
      <div style={{ background: "#fff", borderRadius: 16, padding: 28, maxWidth: 620, width: "100%", maxHeight: "90vh", overflowY: "auto", boxShadow: "0 24px 64px rgba(0,0,0,.18)" }}
        onClick={e => e.stopPropagation()}>
        <div style={{ fontFamily: "Fraunces, serif", fontSize: 20, fontWeight: 300, color: "var(--txt)", marginBottom: 4 }}>Vystavit fakturu</div>
        <div style={{ fontSize: 12.5, color: "var(--mut)", marginBottom: 20 }}>{client?.name}</div>

        {/* Entry selection */}
        <div style={{ fontSize: 9.5, letterSpacing: ".12em", textTransform: "uppercase", color: "var(--mut)", fontWeight: 500, marginBottom: 10 }}>Výkazy k fakturaci</div>
        <div style={{ border: "1px solid var(--line)", borderRadius: 10, overflow: "hidden", marginBottom: 20 }}>
          {entries.sort((a,b)=>(a.entry_date||"").localeCompare(b.entry_date||"")).map(e => (
            <label key={e.id} style={{ display: "flex", alignItems: "flex-start", gap: 12, padding: "11px 14px", borderBottom: "1px solid var(--line)", cursor: "pointer", background: selected.has(e.id) ? "#F7F5FF" : "#fff", transition: ".1s" }}>
              <input type="checkbox" checked={selected.has(e.id)} onChange={() => toggle(e.id)} style={{ marginTop: 2, accentColor: "var(--ink)", flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12.5, color: "var(--txt)", fontWeight: 500 }}>{fmtDate(e.entry_date)} — {e.description?.slice(0, 80)}</div>
                <div style={{ fontSize: 11, color: "var(--mut)", marginTop: 2 }}>
                  {e.hours > 0 && `${e.hours} h × ${fmtKc(e.rate)}`}
                  {e.notary_fee > 0 && ` · notář ${fmtKc(e.notary_fee)}`}
                  {e.admin_fee > 0 && ` · sp.pop. ${fmtKc(e.admin_fee)}`}
                </div>
              </div>
              <div style={{ fontSize: 12.5, fontFamily: "Fraunces, serif", fontWeight: 300, color: "var(--ink)", flexShrink: 0 }}>{fmtKc(e.amount)}</div>
            </label>
          ))}
        </div>

        {/* Invoice fields */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 20 }}>
          <label className="field">
            <span>Číslo faktury</span>
            <input value={invoiceNo} onChange={e => setInvoiceNo(e.target.value)} />
          </label>
          <label className="field">
            <span>Variabilní symbol</span>
            <input value={varSymbol} onChange={e => setVarSymbol(e.target.value)} />
          </label>
          <label className="field">
            <span>Datum vystavení</span>
            <input type="date" value={issueDate} onChange={e => { setIssueDate(e.target.value); setDueDateBase(nextDueDate(e.target.value)); setDueDateOffset(0); }} />
          </label>
          <div className="field">
            <span>DUZP (auto)</span>
            <div style={{ padding: "8px 10px", background: "var(--bg)", borderRadius: 8, border: "1px solid var(--line)", fontSize: 13, color: "var(--mut)" }}>{fmtDate(duzp)}</div>
          </div>
          {/* Due date stepper */}
          <div className="field" style={{ gridColumn: "1 / -1" }}>
            <span>Datum splatnosti</span>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <button style={stepStyle} onClick={() => setDueDateOffset(o => Math.max(-5, o-1))} disabled={dueDateOffset <= -5}>−</button>
              <div style={{ flex: 1, padding: "8px 12px", background: dueDateOffset !== 0 ? "#F0EEFF" : "var(--bg)", borderRadius: 8, border: "1px solid var(--line)", fontSize: 13, color: "var(--ink)", textAlign: "center", fontWeight: dueDateOffset !== 0 ? 500 : 400 }}>
                {fmtDate(dueDate)}
                {dueDateOffset !== 0 && <span style={{ fontSize: 10, color: "var(--mut)", marginLeft: 8 }}>{dueDateOffset > 0 ? `+${dueDateOffset}` : dueDateOffset} dní od 15.</span>}
              </div>
              <button style={stepStyle} onClick={() => setDueDateOffset(o => Math.min(5, o+1))} disabled={dueDateOffset >= 5}>+</button>
            </div>
          </div>
        </div>

        {/* Summary */}
        <div style={{ background: "var(--bg)", borderRadius: 10, padding: "14px 16px", marginBottom: 20, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ fontSize: 12, color: "var(--mut)" }}>
            {selEntries.length} výkazů · základ {fmtKc(workAmt)}
            {(notary + admin) > 0 && <span> · přefakturace {fmtKc(notary + admin)}</span>}
          </div>
          <div style={{ fontFamily: "Fraunces, serif", fontSize: 20, fontWeight: 300, color: "var(--ink)" }}>{fmtKc(total)}</div>
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          <button className="btn" style={{ flex: 1 }} onClick={onCancel}>Zrušit</button>
          <button className="btn pri" style={{ flex: 2 }} onClick={() => setShowPreview(true)} disabled={selEntries.length === 0}>
            Náhled faktury →
          </button>
        </div>
      </div>
    </div>
  );
}

